import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface CurrentCycle {
  cycleDay: number;
  phase: string;
  daysUntilNextPeriod: number;
}

interface PredictedDates {
  nextPeriodStart: string;
  nextOvulation: string;
}

interface CycleData {
  currentCycle: CurrentCycle;
  predictedDates: PredictedDates;
  cycleLength: number;
}

export default function Widget() {
  const cycleData = response.data as CycleData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 420, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF69B4' }}>
              Cycle Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Current Day: {cycleData.currentCycle.cycleDay}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Phase: {cycleData.currentCycle.phase}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Days Until Next Period: {cycleData.currentCycle.daysUntilNextPeriod}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Predicted Dates
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip
                label={`Next Period: ${cycleData.predictedDates.nextPeriodStart}`}
                sx={{ fontSize: '11px', px: 1 }}
              />
              <Chip
                label={`Next Ovulation: ${cycleData.predictedDates.nextOvulation}`}
                sx={{ fontSize: '11px', px: 1 }}
              />
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Cycle Length
            </Typography>
            <Typography variant="h6" fontWeight={500} sx={{ color: '#8B0000' }}>
              {cycleData.cycleLength} days
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
